import React, { useState, useEffect } from 'react';
import { Search, Package, MapPin, Clock, CheckCircle, AlertCircle } from 'lucide-react';
import { useAuth } from '../contexts/AuthContext';
import { toast } from 'sonner';

const Pesanan = () => {
  const { user } = useAuth();
  const [activeTab, setActiveTab] = useState('tracking');
  const [trackingNumber, setTrackingNumber] = useState('');
  const [trackingResult, setTrackingResult] = useState(null);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    phone: '',
    origin: '',
    destination: '',
    weight: '',
    description: '',
    serviceType: 'darat',
  });

  useEffect(() => {
    const urlParams = new URLSearchParams(window.location.search);
    const resiParam = urlParams.get('resi');
    if (resiParam) {
      setTrackingNumber(resiParam);
      handleTrackShipment(resiParam);
    }

    const hash = window.location.hash;
    if (hash === '#form-penawaran') {
      setActiveTab('penawaran');
    }
  }, []);

  const handleTrackShipment = (resi = trackingNumber) => {
    if (!resi.trim()) {
      toast.error('Masukkan nomor resi');
      return;
    }

    // Get tracking data from localStorage
    const shipments = JSON.parse(localStorage.getItem('shipments') || '[]');
    const found = shipments.find((s) => s.trackingNumber === resi);

    if (found) {
      setTrackingResult(found);
      toast.success('Paket ditemukan!');
    } else {
      // Generate dummy tracking data if not found
      const dummyTracking = {
        trackingNumber: resi,
        status: 'in_transit',
        origin: 'Jakarta',
        destination: 'Surabaya',
        estimatedDelivery: '25 Jan 2024',
        currentLocation: 'Semarang Distribution Center',
        history: [
          {
            date: '22 Jan 2024 09:00',
            status: 'Paket diterima di origin',
            location: 'Jakarta',
          },
          {
            date: '22 Jan 2024 15:30',
            status: 'Dalam perjalanan',
            location: 'Jakarta - Semarang',
          },
          {
            date: '23 Jan 2024 08:00',
            status: 'Tiba di distribution center',
            location: 'Semarang',
          },
          {
            date: '23 Jan 2024 14:00',
            status: 'Sedang dalam proses sortir',
            location: 'Semarang Distribution Center',
          },
        ],
      };
      setTrackingResult(dummyTracking);
      toast.success('Paket ditemukan!');
    }
  };

  const handleSubmitQuote = (e) => {
    e.preventDefault();

    if (!user) {
      toast.error('Silakan login terlebih dahulu');
      setTimeout(() => {
        window.location.href = '/masuk';
      }, 1500);
      return;
    }

    // Save quote request to localStorage
    const quotes = JSON.parse(localStorage.getItem('quotes') || '[]');
    const newQuote = {
      id: Date.now(),
      ...formData,
      userEmail: user.email,
      createdAt: new Date().toISOString(),
      status: 'pending',
    };
    quotes.push(newQuote);
    localStorage.setItem('quotes', JSON.stringify(quotes));

    toast.success('Permintaan penawaran berhasil dikirim! Tim kami akan menghubungi Anda segera.');

    // Reset form
    setFormData({
      name: '',
      email: '',
      phone: '',
      origin: '',
      destination: '',
      weight: '',
      description: '',
      serviceType: 'darat',
    });
  };

  const handleInputChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value,
    });
  };

  const getStatusIcon = (status) => {
    switch (status) {
      case 'delivered':
        return <CheckCircle className="h-6 w-6 text-green-500" />;
      case 'in_transit':
        return <Clock className="h-6 w-6 text-blue-500" />;
      default:
        return <Package className="h-6 w-6 text-gray-500" />;
    }
  };

  const getStatusText = (status) => {
    switch (status) {
      case 'delivered':
        return 'Terkirim';
      case 'in_transit':
        return 'Dalam Perjalanan';
      case 'pending':
        return 'Menunggu Pickup';
      default:
        return 'Unknown';
    }
  };

  return (
    <div className="min-h-screen bg-gray-50" data-testid="pesanan-page">
      {/* Hero Section */}
      <section className="bg-gradient-to-r from-[#0A2647] to-[#144272] text-white py-20">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 text-center">
          <h1 className="text-4xl sm:text-5xl font-bold mb-6" data-testid="pesanan-title">
            Pesanan & Tracking
          </h1>
          <p className="text-lg text-gray-200 max-w-3xl mx-auto">
            Lacak paket Anda atau ajukan permintaan penawaran untuk pengiriman baru
          </p>
        </div>
      </section>

      {/* Tabs */}
      <section className="py-8 bg-white shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex border-b">
            <button
              onClick={() => setActiveTab('tracking')}
              className={`px-8 py-4 font-semibold transition-colors ${
                activeTab === 'tracking'
                  ? 'text-[#0A2647] border-b-2 border-[#D97706]'
                  : 'text-gray-500 hover:text-[#0A2647]'
              }`}
              data-testid="tab-tracking"
            >
              Lacak Pengiriman
            </button>
            <button
              onClick={() => setActiveTab('penawaran')}
              className={`px-8 py-4 font-semibold transition-colors ${
                activeTab === 'penawaran'
                  ? 'text-[#0A2647] border-b-2 border-[#D97706]'
                  : 'text-gray-500 hover:text-[#0A2647]'
              }`}
              data-testid="tab-penawaran"
            >
              Minta Penawaran
            </button>
          </div>
        </div>
      </section>

      {/* Content */}
      <section className="py-16">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          {activeTab === 'tracking' ? (
            <div className="max-w-4xl mx-auto">
              {/* Tracking Input */}
              <div className="bg-white p-8 shadow-lg mb-8">
                <h2 className="text-2xl font-bold text-[#0A2647] mb-6">
                  Lacak Paket Anda
                </h2>
                <div className="flex gap-4">
                  <input
                    type="text"
                    placeholder="Masukkan nomor resi pengiriman..."
                    value={trackingNumber}
                    onChange={(e) => setTrackingNumber(e.target.value)}
                    onKeyPress={(e) => e.key === 'Enter' && handleTrackShipment()}
                    className="flex-1 px-6 py-4 border border-gray-300 focus:outline-none focus:ring-2 focus:ring-[#D97706]"
                    data-testid="tracking-input"
                  />
                  <button
                    onClick={() => handleTrackShipment()}
                    className="px-8 py-4 bg-[#D97706] text-white font-semibold hover:bg-[#B45309] transition-colors flex items-center gap-2"
                    data-testid="track-button"
                  >
                    <Search className="h-5 w-5" /> Lacak
                  </button>
                </div>
              </div>

              {/* Tracking Result */}
              {trackingResult && (
                <div className="bg-white p-8 shadow-lg" data-testid="tracking-result">
                  <div className="border-b pb-6 mb-6">
                    <div className="flex items-center justify-between mb-4">
                      <div>
                        <h3 className="text-2xl font-bold text-[#0A2647] mb-2">
                          Status Pengiriman
                        </h3>
                        <p className="text-gray-600">
                          Resi: <span className="font-semibold">{trackingResult.trackingNumber}</span>
                        </p>
                      </div>
                      <div className="flex items-center gap-2">
                        {getStatusIcon(trackingResult.status)}
                        <span className="font-semibold text-lg">
                          {getStatusText(trackingResult.status)}
                        </span>
                      </div>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mt-6">
                      <div className="flex items-start gap-3">
                        <MapPin className="h-6 w-6 text-[#D97706] flex-shrink-0" />
                        <div>
                          <p className="text-sm text-gray-600">Asal</p>
                          <p className="font-semibold text-[#0A2647]">{trackingResult.origin}</p>
                        </div>
                      </div>
                      <div className="flex items-start gap-3">
                        <MapPin className="h-6 w-6 text-[#D97706] flex-shrink-0" />
                        <div>
                          <p className="text-sm text-gray-600">Tujuan</p>
                          <p className="font-semibold text-[#0A2647]">{trackingResult.destination}</p>
                        </div>
                      </div>
                      <div className="flex items-start gap-3">
                        <Clock className="h-6 w-6 text-[#D97706] flex-shrink-0" />
                        <div>
                          <p className="text-sm text-gray-600">Estimasi Tiba</p>
                          <p className="font-semibold text-[#0A2647]">
                            {trackingResult.estimatedDelivery}
                          </p>
                        </div>
                      </div>
                    </div>
                  </div>

                  {/* Current Location */}
                  <div className="bg-blue-50 p-6 mb-6">
                    <div className="flex items-center gap-3">
                      <Package className="h-8 w-8 text-blue-600" />
                      <div>
                        <p className="text-sm text-gray-600">Lokasi Saat Ini</p>
                        <p className="font-bold text-[#0A2647] text-lg">
                          {trackingResult.currentLocation}
                        </p>
                      </div>
                    </div>
                  </div>

                  {/* History Timeline */}
                  <div>
                    <h4 className="text-xl font-bold text-[#0A2647] mb-6">Riwayat Pengiriman</h4>
                    <div className="space-y-6">
                      {trackingResult.history?.map((item, index) => (
                        <div key={index} className="flex gap-4" data-testid={`history-${index}`}>
                          <div className="flex flex-col items-center">
                            <div className="w-4 h-4 bg-[#D97706] rounded-full"></div>
                            {index < trackingResult.history.length - 1 && (
                              <div className="w-0.5 h-full bg-gray-300 my-1"></div>
                            )}
                          </div>
                          <div className="flex-1 pb-6">
                            <p className="text-sm text-gray-500">{item.date}</p>
                            <p className="font-semibold text-[#0A2647]">{item.status}</p>
                            <p className="text-sm text-gray-600">{item.location}</p>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                </div>
              )}
            </div>
          ) : (
            <div className="max-w-4xl mx-auto" id="form-penawaran">
              <div className="bg-white p-8 shadow-lg">
                <h2 className="text-2xl font-bold text-[#0A2647] mb-6">
                  Form Permintaan Penawaran
                </h2>
                <form onSubmit={handleSubmitQuote} className="space-y-6">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div>
                      <label className="block text-sm font-semibold text-gray-700 mb-2">
                        Nama Lengkap *
                      </label>
                      <input
                        type="text"
                        name="name"
                        value={formData.name}
                        onChange={handleInputChange}
                        required
                        className="w-full px-4 py-3 border border-gray-300 focus:outline-none focus:ring-2 focus:ring-[#D97706]"
                        data-testid="quote-name"
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-semibold text-gray-700 mb-2">
                        Email *
                      </label>
                      <input
                        type="email"
                        name="email"
                        value={formData.email}
                        onChange={handleInputChange}
                        required
                        className="w-full px-4 py-3 border border-gray-300 focus:outline-none focus:ring-2 focus:ring-[#D97706]"
                        data-testid="quote-email"
                      />
                    </div>
                  </div>

                  <div>
                    <label className="block text-sm font-semibold text-gray-700 mb-2">
                      Nomor Telepon *
                    </label>
                    <input
                      type="tel"
                      name="phone"
                      value={formData.phone}
                      onChange={handleInputChange}
                      required
                      className="w-full px-4 py-3 border border-gray-300 focus:outline-none focus:ring-2 focus:ring-[#D97706]"
                      data-testid="quote-phone"
                    />
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div>
                      <label className="block text-sm font-semibold text-gray-700 mb-2">
                        Kota Asal *
                      </label>
                      <input
                        type="text"
                        name="origin"
                        value={formData.origin}
                        onChange={handleInputChange}
                        required
                        className="w-full px-4 py-3 border border-gray-300 focus:outline-none focus:ring-2 focus:ring-[#D97706]"
                        data-testid="quote-origin"
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-semibold text-gray-700 mb-2">
                        Kota Tujuan *
                      </label>
                      <input
                        type="text"
                        name="destination"
                        value={formData.destination}
                        onChange={handleInputChange}
                        required
                        className="w-full px-4 py-3 border border-gray-300 focus:outline-none focus:ring-2 focus:ring-[#D97706]"
                        data-testid="quote-destination"
                      />
                    </div>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div>
                      <label className="block text-sm font-semibold text-gray-700 mb-2">
                        Estimasi Berat (kg) *
                      </label>
                      <input
                        type="number"
                        name="weight"
                        value={formData.weight}
                        onChange={handleInputChange}
                        required
                        min="1"
                        className="w-full px-4 py-3 border border-gray-300 focus:outline-none focus:ring-2 focus:ring-[#D97706]"
                        data-testid="quote-weight"
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-semibold text-gray-700 mb-2">
                        Jenis Layanan *
                      </label>
                      <select
                        name="serviceType"
                        value={formData.serviceType}
                        onChange={handleInputChange}
                        className="w-full px-4 py-3 border border-gray-300 focus:outline-none focus:ring-2 focus:ring-[#D97706]"
                        data-testid="quote-service-type"
                      >
                        <option value="darat">Pengiriman Darat</option>
                        <option value="laut">Pengiriman Laut</option>
                        <option value="udara">Pengiriman Udara</option>
                        <option value="express">Express Service</option>
                      </select>
                    </div>
                  </div>

                  <div>
                    <label className="block text-sm font-semibold text-gray-700 mb-2">
                      Deskripsi Barang
                    </label>
                    <textarea
                      name="description"
                      value={formData.description}
                      onChange={handleInputChange}
                      rows="4"
                      className="w-full px-4 py-3 border border-gray-300 focus:outline-none focus:ring-2 focus:ring-[#D97706]"
                      placeholder="Jelaskan jenis barang yang akan dikirim..."
                      data-testid="quote-description"
                    ></textarea>
                  </div>

                  <div className="pt-4">
                    <button
                      type="submit"
                      className="w-full px-8 py-4 bg-[#D97706] text-white text-lg font-semibold hover:bg-[#B45309] transition-colors"
                      data-testid="submit-quote-button"
                    >
                      Kirim Permintaan Penawaran
                    </button>
                  </div>
                </form>
              </div>
            </div>
          )}
        </div>
      </section>
    </div>
  );
};

export default Pesanan;
